def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    n, m = points.shape
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # Hypervolume cache
    hv_cache = {}

    def compute_hv(indices):
        key = frozenset(indices)
        if key in hv_cache:
            return hv_cache[key]
        if not indices:
            hv_cache[key] = 0.0
            return 0.0
        data = points[list(indices), :]
        hv = pg.hypervolume(data)
        value = hv.compute(reference_point)
        hv_cache[key] = value
        return value

    # 1. Greedy initialization
    def greedy_initialization():
        current_set = set()
        for _ in range(k):
            best_gain = -float('inf')
            best_idx = None
            for idx in range(n):
                if idx in current_set:
                    continue
                temp_set = current_set | {idx}
                gain = compute_hv(temp_set) - compute_hv(current_set)
                if gain > best_gain:
                    best_gain = gain
                    best_idx = idx
            if best_idx is not None:
                current_set.add(best_idx)
        return current_set

    # 2. Initialize population with greedy solution and variations
    population = []
    pop_size = 30

    # Add greedy solution
    greedy_sol = greedy_initialization()
    population.append((greedy_sol, compute_hv(greedy_sol), len(greedy_sol)))

    # Add random variations
    for _ in range(pop_size - 1):
        if random.random() < 0.7:
            # Perturb greedy solution
            sol = set(greedy_sol)
            # Adaptive mutation based on size
            mutation_rate = min(0.3, 1.0 / (2 * k))

            # Remove some points
            if len(sol) > 1:
                for idx in list(sol):
                    if random.random() < mutation_rate:
                        sol.remove(idx)

            # Add points with high contribution
            while len(sol) < k and len(sol) < n:
                available = set(range(n)) - sol
                if not available:
                    break
                # Quick greedy addition
                best_gain = -float('inf')
                best_idx = None
                # Sample only some candidates for speed
                candidates = random.sample(list(available), min(10, len(available)))
                for idx in candidates:
                    temp = sol | {idx}
                    gain = compute_hv(temp) - compute_hv(sol)
                    if gain > best_gain:
                        best_gain = gain
                        best_idx = idx
                if best_idx is not None:
                    sol.add(best_idx)
        else:
            # Random solution
            size = random.randint(max(1, k-2), min(k+2, n))
            indices = set(random.sample(range(n), size))
            sol = indices

        # Ensure size constraint
        while len(sol) > k:
            # Remove point with smallest contribution
            worst_idx = None
            worst_contrib = float('inf')
            for idx in list(sol):
                temp = sol - {idx}
                contrib = compute_hv(sol) - compute_hv(temp)
                if contrib < worst_contrib:
                    worst_contrib = contrib
                    worst_idx = idx
            if worst_idx is not None:
                sol.remove(worst_idx)

        while len(sol) < k and len(sol) < n:
            # Add point with largest contribution
            available = set(range(n)) - sol
            if available:
                best_idx = None
                best_gain = -float('inf')
                # Sample candidates for speed
                candidates = random.sample(list(available), min(15, len(available)))
                for idx in candidates:
                    temp = sol | {idx}
                    gain = compute_hv(temp) - compute_hv(sol)
                    if gain > best_gain:
                        best_gain = gain
                        best_idx = idx
                if best_idx is not None:
                    sol.add(best_idx)

        population.append((sol, compute_hv(sol), len(sol)))

    # 3. Evolutionary search with contribution-guided operators
    max_generations = 50

    for gen in range(max_generations):
        # Environmental selection
        population.sort(key=lambda x: (-x[1], x[2]))
        population = population[:pop_size]

        # Generate offspring
        offspring = []
        for _ in range(pop_size // 2):
            # Tournament selection
            idx1, idx2 = random.sample(range(len(population)), 2)
            parent1 = population[idx1][0]
            parent2 = population[idx2][0]

            # Crossover
            if random.random() < 0.8:
                child = set()
                # Take union of parents
                union_set = parent1 | parent2
                if len(union_set) <= k:
                    child = union_set
                else:
                    # Select k points with highest individual contributions
                    contribs = []
                    for idx in union_set:
                        single_set = {idx}
                        contrib = compute_hv(single_set)
                        contribs.append((contrib, idx))
                    contribs.sort(reverse=True)
                    child = {idx for _, idx in contribs[:k]}
            else:
                child = set(parent1)

            # Contribution-guided mutation
            if child:
                # Adaptive mutation rate
                mutation_rate = min(0.4, 1.0 / (2 * len(child)))

                # Remove worst points with probability
                if random.random() < mutation_rate and len(child) > 1:
                    # Find worst contributor
                    worst_idx = None
                    worst_contrib = float('inf')
                    for idx in list(child):
                        temp = child - {idx}
                        contrib = compute_hv(child) - compute_hv(temp)
                        if contrib < worst_contrib:
                            worst_contrib = contrib
                            worst_idx = idx
                    if worst_idx is not None:
                        child.remove(worst_idx)

                # Add best available points with probability
                if random.random() < mutation_rate and len(child) < n:
                    available = set(range(n)) - child
                    if available:
                        # Find best addition
                        best_idx = None
                        best_gain = -float('inf')
                        # Sample for speed
                        candidates = random.sample(list(available), min(10, len(available)))
                        for idx in candidates:
                            temp = child | {idx}
                            gain = compute_hv(temp) - compute_hv(child)
                            if gain > best_gain:
                                best_gain = gain
                                best_idx = idx
                        if best_idx is not None:
                            child.add(best_idx)

            # Ensure size constraint
            while len(child) > k:
                # Remove worst contributor
                worst_idx = None
                worst_contrib = float('inf')
                for idx in list(child):
                    temp = child - {idx}
                    contrib = compute_hv(child) - compute_hv(temp)
                    if contrib < worst_contrib:
                        worst_contrib = contrib
                        worst_idx = idx
                if worst_idx is not None:
                    child.remove(worst_idx)

            while len(child) < k and len(child) < n:
                # Add best contributor
                available = set(range(n)) - child
                if available:
                    best_idx = None
                    best_gain = -float('inf')
                    candidates = random.sample(list(available), min(15, len(available)))
                    for idx in candidates:
                        temp = child | {idx}
                        gain = compute_hv(temp) - compute_hv(child)
                        if gain > best_gain:
                            best_gain = gain
                            best_idx = idx
                    if best_idx is not None:
                        child.add(best_idx)

            if child:
                hv = compute_hv(child)
                offspring.append((child, hv, len(child)))

        # Combine and select
        population.extend(offspring)

    # 4. Final selection and local search
    population.sort(key=lambda x: (-x[1], x[2]))
    best_solution = population[0][0]

    # Quick local search on best solution
    improved = True
    while improved:
        improved = False
        current_hv = compute_hv(best_solution)

        # Try swaps
        S_list = list(best_solution)
        available = set(range(n)) - best_solution

        for s_idx in S_list:
            for r_idx in available:
                new_set = (best_solution - {s_idx}) | {r_idx}
                new_hv = compute_hv(new_set)
                if new_hv > current_hv:
                    best_solution = new_set
                    current_hv = new_hv
                    improved = True
                    break
            if improved:
                break

    # Ensure exactly k points
    best_indices = list(best_solution)
    if len(best_indices) > k:
        # Remove worst points
        while len(best_indices) > k:
            worst_idx = None
            worst_contrib = float('inf')
            for idx in best_indices:
                temp_set = set(best_indices) - {idx}
                contrib = compute_hv(set(best_indices)) - compute_hv(temp_set)
                if contrib < worst_contrib:
                    worst_contrib = contrib
                    worst_idx = idx
            if worst_idx is not None:
                best_indices.remove(worst_idx)
    elif len(best_indices) < k:
        # Add best points
        available = set(range(n)) - set(best_indices)
        while len(best_indices) < k and available:
            best_idx = None
            best_gain = -float('inf')
            for idx in available:
                temp_set = set(best_indices) | {idx}
                gain = compute_hv(temp_set) - compute_hv(set(best_indices))
                if gain > best_gain:
                    best_gain = gain
                    best_idx = idx
            if best_idx is not None:
                best_indices.append(best_idx)
                available.remove(best_idx)

    return points[best_indices, :]

def HSS(points, k: int, reference_point) -> np.ndarray:
    n, m = points.shape

    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")

    # 创建索引列表
    R_indices = list(range(n))
    R_objectives_array = points
    random.shuffle(R_indices)

    # 1. GSI算法 - 初始化
    S = set(R_indices[:k])
    elements_to_insert = R_indices[k:]

    # 2. GSI算法 - 迭代过程
    for element_to_add in elements_to_insert:
        S.add(element_to_add)

        worst_element_index = None
        min_contribution = float('inf')

        # 获取当前 S 的超体积
        if not S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        for s_index in list(S):
            # 尝试移除 s_index: S_temp = S - {s_index}
            S_temp = S - {s_index}

            # 移除后的超体积
            if not S_temp:
                M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                temp_selected = np.empty((0, M))
            else:
                temp_selected = R_objectives_array[list(S_temp)]

            if temp_selected.size == 0:
                hv_after_remove = 0.0
            else:
                try:
                    hv = pg.hypervolume(temp_selected)
                    hv_after_remove = hv.compute(reference_point)
                except Exception as e:
                    print(f"Hypervolume calculation error: {e}")
                    hv_after_remove = 0.0

            # 贡献度 = 移除前的 HV - 移除后的 HV
            contribution = current_hv - hv_after_remove

            if contribution < min_contribution:
                min_contribution = contribution
                worst_element_index = s_index

        if worst_element_index is not None:
            S.remove(worst_element_index)

    # 3. LS算法 - 初始化
    current_S = set(S)
    R_set = set(R_indices)

    if len(current_S) != k:
        raise ValueError("初始子集 S 的大小必须等于 k。")

    # 4. LS算法 - 迭代过程
    while True:
        # 获取当前 S 的超体积
        if not current_S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(current_S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        found_improvement = False

        R_minus_S = list(R_set - current_S)
        S_list = list(current_S)

        # 遍历所有可能的交换对 (s, r)
        for s_index in S_list:
            for r_index in R_minus_S:
                # 尝试交换: S' = S - {s_index} + {r_index}
                S_new = (current_S - {s_index}) | {r_index}

                # 计算新集合 S_new 的超体积
                if not S_new:
                    M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                    new_selected = np.empty((0, M))
                else:
                    new_selected = R_objectives_array[list(S_new)]

                if new_selected.size == 0:
                    new_hv = 0.0
                else:
                    try:
                        hv = pg.hypervolume(new_selected)
                        new_hv = hv.compute(reference_point)
                    except Exception as e:
                        print(f"Hypervolume calculation error: {e}")
                        new_hv = 0.0

                # 检查是否是改进
                if new_hv > current_hv:
                    current_S = S_new
                    found_improvement = True
                    break  # 跳出 r_index 循环

            if found_improvement:
                break  # 跳出 s_index 循环

        if not found_improvement:
            break

    # 5. 返回选择的点
    if not current_S:
        M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
        selected_points = np.empty((0, M))
    else:
        selected_points = R_objectives_array[list(current_S)]

    return selected_points
